resources.afterResponseScript:
const status = insomnia.response.code;
insomnia.test("Categories returns 200", () => {
  insomnia.expect(status).to.eql(200);
});

const body = insomnia.response.json();
insomnia.test("Categories returns array", () => {
  insomnia.expect(body).to.be.an("array");
});

const status = insomnia.response.code;
insomnia.test("Login returns 200", () => {
  insomnia.expect(status).to.eql(200);
});

const body = insomnia.response.json();
insomnia.test("Login response has token and user", () => {
  insomnia.expect(body).to.have.property("token");
  insomnia.expect(body).to.have.property("user");
  insomnia.expect(body.user).to.have.property("id");
});

if (body && body.token) {
  insomnia.environment.set("token", body.token);
}
if (body && body.user && body.user.id !== undefined) {
  insomnia.environment.set("user_id", body.user.id);
}

const status = insomnia.response.code;
insomnia.test("Auctions list returns 200", () => {
  insomnia.expect(status).to.eql(200);
});

const body = insomnia.response.json();
insomnia.test("Auctions list returns array", () => {
  insomnia.expect(body).to.be.an("array");
});

const status = insomnia.response.code;
insomnia.test("Auction detail status is valid", () => {
  insomnia.expect(status).to.be.oneOf([200, 404]);
});

if (status === 200) {
  const body = insomnia.response.json();
  insomnia.test("Auction detail has id", () => {
    insomnia.expect(body).to.have.property("id");
  });
}

const status = insomnia.response.code;
