const status = insomnia.response.code;
insomnia.test("Create auction status is valid", () => {
  insomnia.expect(status).to.be.oneOf([200, 400, 401]);
});

const status = insomnia.response.code;
insomnia.test("Update auction currently not implemented or unauthorized", () => {
  insomnia.expect(status).to.be.oneOf([501, 401]);
