const status = insomnia.response.code;
insomnia.test("Create user status is valid", () => {
  insomnia.expect(status).to.be.oneOf([201, 400]);
});

const status = insomnia.response.code;
insomnia.test("Get users status is valid", () => {
  insomnia.expect(status).to.be.oneOf([200, 401]);
});

